import unittest

class TestSolution(unittest.TestCase):
    def test_basic_40th_percentile(self):
        self.assertEqual(compute_percentile([15, 20, 35, 40, 50], 40), 20)

    def test_basic_25th_percentile(self):
        self.assertEqual(compute_percentile([3, 6, 7, 8, 8, 10, 13, 15, 16, 20], 25), 7)

    def test_basic_75th_percentile(self):
        self.assertEqual(compute_percentile([3, 6, 7, 8, 8, 10, 13, 15, 16, 20], 75), 15)

    def test_hidden_single_element(self):
        self.assertEqual(compute_percentile([100], 50), 100)

    def test_hidden_single_element_p100(self):
        self.assertEqual(compute_percentile([42], 100), 42)

    def test_hidden_two_elements_p50(self):
        self.assertEqual(compute_percentile([1, 2], 50), 1)

    def test_hidden_two_elements_p100(self):
        self.assertEqual(compute_percentile([1, 2], 100), 2)

    def test_hidden_unsorted_p100(self):
        self.assertEqual(compute_percentile([5, 1, 9, 3, 7], 100), 9)

    def test_hidden_unsorted_p1(self):
        self.assertEqual(compute_percentile([5, 1, 9, 3, 7], 1), 1)

    def test_hidden_duplicates_median(self):
        self.assertEqual(compute_percentile([4, 4, 4, 4, 4], 50), 4)

    def test_hidden_50th_percentile(self):
        self.assertEqual(compute_percentile([15, 20, 35, 40, 50], 50), 35)

